module multi_16bit(
    input clk,
    input rst_n,
    input start,
    input [15:0] ain,
    input [15:0] bin,
    output reg [31:0] yout,
    output reg done
);

reg [15:0] a, b;
reg [31:0] product;
reg [4:0] count;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        a <= 0;
        b <= 0;
        product <= 0;
        count <= 0;
        done <= 0;
    end
    else if (start) begin
        a <= ain;
        b <= bin;
        product <= 0;
        count <= 16;
        done <= 0;
    end
    else if (count > 0) begin
        if (b[0]) begin
            product <= product + (a << (16 - count));
        end
        b <= b >> 1;
        count <= count - 1;
        if (count == 1) begin
            yout <= product;
            done <= 1;
        end
    end
end

endmodule
